<template>
  <div class="home">
    <v-col lg="10" xl="8" class="mx-auto">
      <v-carousel cycle :interval="3000" class="mb-3 elevation-4" >
        <v-carousel-item
          v-for="item in carouselItems"
          :key="item.id"
          :src="item.src"
          reverse-transition="fade-transition"
          transition="fade-transition"
        ></v-carousel-item>
      </v-carousel>

      <h1 class="display-3 primary--text text-center">Pokemons</h1>
      <v-divider class="my-3"></v-divider>
      <v-pagination
        v-model="page"
        circle
        :length="length"
        :disabled="isFetching"
        next-icon="mdi-chevron-right"
        prev-icon="mdi-chevron-left"
        :page="page"
        :total-visible="9"
      ></v-pagination>

      <v-row>
        <v-col
          cols="12"
          lg="3"
          md="4"
          sm="6"
          v-for="item in list"
          :key="item.id"
        >
          <v-hover v-slot:default="{ hover }">
            <v-card :elevation="hover ? 12 : 6" :class="{ 'on-hover': hover }">
              <v-hover v-slot:default="{ hover }">
                <v-img
                  class="white--text align-end"
                  contain
                  :src="
                    `https://pokeres.bastionbot.org/images/pokemon/${item.id}.png`
                  "
                  :lazy-src="
                    `https://pokeres.bastionbot.org/images/pokemon/${item.id}.png`
                  "
                  :alt="item.name"
                  height="200px"
                >
                  <template v-slot:placeholder>
                    <v-row
                      class="fill-height ma-0"
                      align="center"
                      justify="center"
                    >
                      <v-progress-circular
                        indeterminate
                        color="secondary lighten-1"
                      ></v-progress-circular>
                    </v-row>
                  </template>
                  <v-fade-transition>
                    <v-overlay v-if="hover" absolute color="red lighten-1">
                      <v-btn
                        color="secondary"
                        ripple
                        @click="openDetails(item.id)"
                        >See more info</v-btn
                      >
                    </v-overlay>
                  </v-fade-transition>
                </v-img>
              </v-hover>

              <v-divider></v-divider>

              <v-card-title>Name: {{ item.name }}</v-card-title>

              <v-card-subtitle>Id: {{ item.id }}</v-card-subtitle>

              <v-card-text style="position: relative;">
                <v-btn
                  absolute
                  :color="isPokemonInCompareList(item.id) ? 'error' : 'success'"
                  fab
                  right
                  bottom
                  @click="updateComparePokemons(item.id)"
                >
                  <v-icon
                    >mdi-{{
                      isPokemonInCompareList(item.id) ? "minus" : "plus"
                    }}</v-icon
                  >
                </v-btn>
              </v-card-text>

              <v-card-actions>
                <v-btn color="primary" text @click="openDetails(item.id)">
                  Explore
                </v-btn>
              </v-card-actions>
            </v-card>
          </v-hover>
        </v-col>
      </v-row>

      <v-pagination
        v-model="page"
        circle
        :length="length"
        :disabled="isFetching"
        next-icon="mdi-chevron-right"
        prev-icon="mdi-chevron-left"
        :page="page"
        :total-visible="9"
      ></v-pagination>
    </v-col>
    <router-view @close-dialog="() => closeDetails()"></router-view>
  </div>
</template>

<script>
import { mapGetters } from "vuex";
import axios from "axios";

export default {
  name: "Home",

  mounted() {
    this.fetchList();
  },
  computed: {
    ...mapGetters(["isPokemonInCompareList"]),
  },
  data() {
    return {
      list: [],
      page: parseInt(this.$route.query.page) || 1,
      hasNext: false,
      hasPrevious: false,
      length: 0,
      size: 24,
      isFetching: true,
      carouselItems: [
        {
          id: "carousel-1",
          src:
            "https://i.pinimg.com/originals/0f/2e/90/0f2e90c1486018aa26c15a27a11fa5d7.jpg",
        },
        {
          id: "carousel-2",
          src:
            "https://i.pinimg.com/originals/51/f8/4f/51f84f464397eff275046ed8c5c29a70.jpg",
        },
        {
          id: "carousel-3",
          src: "https://wallpaperaccess.com/full/20996.jpg",
        },
      ],
    };
  },

  watch: {
    page(newValue, oldValue) {
      if (newValue !== oldValue) {
        this.fetchList().then(() =>
          this.$router.push({ name: "Home", query: { page: newValue } })
        );
      }
    },
  },

  methods: {
    fetchList() {
      this.isFetching = true;
      return axios
        .get(
          `https://pokeapi.co/api/v2/pokemon?offset=${this.size *
            (this.page - 1)}&limit=${this.size}`
        )
        .then((response) => {
          const { data } = response;
          this.list = data.results.map((item) => {
            var id = parseInt(item.url.match(/pokemon\/\d+/)[0].substring(8));
            return { id, ...item };
          });
          this.length = Math.ceil(data.count / this.size);
          this.hasNext = data.next != null;
          this.hasPrevious = data.previous != null;
          this.isFetching = false;
        });
    },
    openDetails(id) {
      this.$router.push({
        name: "PokemonDetailsModal",
        params: { id },
      });
    },
    closeDetails() {
      this.$router.push({
        name: "Home",
        query: { page: this.page },
      });
    },
    updateComparePokemons(id) {
      this.$store
        .dispatch("getPokemon", id)
        .then((response) =>
          this.$store.dispatch("updateComparePokemons", response)
        );
    },
  },
};
</script>
