import Vue from "vue";
import Vuetify from "vuetify/lib";
import colors from "vuetify/lib/util/colors";

Vue.use(Vuetify);

export default new Vuetify({
  theme: {
    options: {
      customProperties: true,
    },
    themes: {
      light: {
        primary:
          localStorage.getItem("theme-light-primary") == null
            ? colors.blue.lighten1
            : localStorage.getItem("theme-light-primary"),
        secondary:
          localStorage.getItem("theme-light-secondary") == null
            ? colors.green.lighten1
            : localStorage.getItem("theme-light-secondary"),
      },
      dark: {
        primary:
          localStorage.getItem("theme-dark-primary") == null
            ? colors.green.lighten1
            : localStorage.getItem("theme-dark-primary"),
        secondary:
          localStorage.getItem("theme-dark-secondary") == null
            ? colors.blue.lighten1
            : localStorage.getItem("theme-dark-secondary"),
      },
    },
  },
});
