<template>
  <v-app id="inspire">
    <v-navigation-drawer
      v-model="drawer"
      app
      clipped
      :expand-on-hover="isExpandOnHover"
      :mini-variant="isMiniNav"
    >
      <v-list dense>
        <v-list-item
          v-for="item in sideBarItems"
          :key="item.link"
          link
          :to="item.link"
        >
          <v-list-item-action>
            <v-icon>{{ item.icon }}</v-icon>
          </v-list-item-action>
          <v-list-item-content>
            <v-list-item-title>{{ item.text }}</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
      </v-list>

      <template v-slot:append>
        <v-divider></v-divider>

        <v-list dense>
          <v-list-item link to="/settings">
            <v-list-item-action>
              <v-icon>mdi-settings</v-icon>
            </v-list-item-action>
            <v-list-item-content>
              <v-list-item-title>Settings</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
        </v-list>
      </template>
    </v-navigation-drawer>

    <v-app-bar
      app
      color="primary"
      dark
      clipped-left
      :collapse-on-scroll="checkCollapseOnScroll"
    >
      <v-app-bar-nav-icon @click.stop="drawer = !drawer" v-if="!isSearching">
      </v-app-bar-nav-icon>
      <v-btn icon @click="isSearching = false" v-else>
        <v-icon>mdi-arrow-left</v-icon>
      </v-btn>

      <template v-if="!isSearching">
        <v-toolbar-title>
          Pokedex App
        </v-toolbar-title>
        <v-spacer></v-spacer>
      </template>
      <template v-else>
        <v-row>
          <v-col cols="12" sm="8" lg="6" class="mx-auto">
            <v-text-field
              :solo-inverted="!isDark"
              :solo="isDark"
              flat
              hide-details
              clearable
              label="Search"
              prepend-inner-icon="mdi-magnify"
              v-model="search"
              @keypress.enter="onSearch"
            ></v-text-field>
          </v-col>
        </v-row>
      </template>

      <v-btn icon @click="isSearching = true" v-if="!isSearching">
        <v-icon>mdi-magnify</v-icon>
      </v-btn>

      <v-menu bottom offset-y :close-on-content-click="false">
        <template v-slot:activator="{ on }">
          <v-btn icon v-on="on">
            <v-icon>mdi-dots-vertical</v-icon>
          </v-btn>
        </template>
        <v-list>
          <v-list-item>
            <v-switch
              v-model="isDark"
              inset
              :label="isDarkThemeLabel"
            ></v-switch>
          </v-list-item>
          <v-list-item link>
            <v-icon class="mr-3">mdi-account</v-icon>
            <v-list-item-content>
              <v-list-item-title>Account</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
          <v-list-item link>
            <v-icon class="mr-3">mdi-alert</v-icon>
            <v-list-item-content>
              <v-list-item-title>Alert</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
        </v-list>

        <v-divider></v-divider>

        <v-list>
          <v-list-item link to="/settings">
            <v-icon class="mr-3">mdi-settings</v-icon>
            <v-list-item-content>
              <v-list-item-title>Settings</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
        </v-list>
      </v-menu>
    </v-app-bar>

    <v-content>
      <v-container fluid>
        <router-view></router-view>
      </v-container>
    </v-content>
    <v-footer app inset absolute>
      <span>&copy; Copyright {{ year }} - made by Dat</span>
    </v-footer>

    <v-fab-transition>
      <v-btn
        v-show="!isBackToTop"
        v-scroll="onScroll"
        color="secondary"
        dark
        fixed
        bottom
        right
        fab
        @click="scrollToTop"
      >
        <v-icon>mdi-arrow-up</v-icon>
      </v-btn>
    </v-fab-transition>
  </v-app>
</template>

<script>
import { mapState } from "vuex";

export default {
  computed: {
    isDarkThemeLabel() {
      return this.isDark ? "Dark" : "Light";
    },
    checkCollapseOnScroll() {
      return !this.isSearching && this.isMiniNav && !this.isExpandOnHover;
    },
    isDark: {
      get() {
        return this.$store.state.isDark;
      },
      set(value) {
        this.$store.commit("updateIsDark", value);
      },
    },
    ...mapState(["isMiniNav", "isExpandOnHover"]),
  },

  data: () => ({
    search: "",
    isSearching: false,
    isBackToTop: true,
    drawer: null,
    year: new Date().getFullYear(),
    sideBarItems: [
      {
        link: "/",
        icon: "mdi-home",
        text: "Home",
      },
      {
        link: "/comparePokemons",
        icon: "mdi-compare",
        text: "Compare Pokemons",
      },
      {
        link: "/about",
        icon: "mdi-contacts",
        text: "About",
      },
    ],
  }),

  methods: {
    onScroll(e) {
      if (typeof window === "undefined") return;
      const top = window.pageYOffset || e.target.scrollTop || 0;
      this.isBackToTop = top < 40;
    },
    scrollToTop() {
      this.$vuetify.goTo(0);
    },
    onSearch() {
      this.search = this.search.trim();
      if (this.search != "") {
        this.$router.push({
          path: "/search",
          query: { s: this.search },
        });
      }
    },
  },
};
</script>
